     1→//! Gallops JSON operations
     2→//!
     3→//! Implements read/write operations on the Gallops JSON store.
     4→//! All operations are atomic (write to temp, then rename).
     5→
     6→use serde::{Deserialize, Serialize};
     7→use crate::jjrf_favor::CHARSET;
     8→use std::collections::HashSet;
     9→use std::fs;
    10→use std::io::Write;
    11→use std::path::Path;
    12→
    13→/// Pace state values
    14→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    15→#[serde(rename_all = "lowercase")]
    16→pub enum PaceState {
    17→    Rough,
    18→    Primed,
    19→    Complete,
    20→    Abandoned,
    21→}
    22→
    23→/// Heat status values
    24→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
    25→#[serde(rename_all = "lowercase")]
    26→pub enum HeatStatus {
    27→    Current,
    28→    Retired,
    29→}
    30→
    31→/// Tack record - snapshot of Pace state and plan
    32→#[derive(Debug, Clone, Serialize, Deserialize)]
    33→pub struct Tack {
    34→    pub ts: String,
    35→    pub state: PaceState,
    36→    pub text: String,
    37→    #[serde(skip_serializing_if = "Option::is_none")]
    38→    pub direction: Option<String>,
    39→}
    40→
    41→/// Pace record - discrete action within a Heat
    42→#[derive(Debug, Clone, Serialize, Deserialize)]
    43→pub struct Pace {
    44→    pub silks: String,
    45→    pub tacks: Vec<Tack>,
    46→}
    47→
    48→/// Heat record - bounded initiative
    49→#[derive(Debug, Clone, Serialize, Deserialize)]
    50→pub struct Heat {
    51→    pub silks: String,
    52→    pub creation_time: String,
    53→    pub status: HeatStatus,
    54→    pub order: Vec<String>,
    55→    pub next_pace_seed: String,
    56→    pub paddock_file: String,
    57→    pub paces: std::collections::HashMap<String, Pace>,
    58→}
    59→
    60→/// Root Gallops structure
    61→#[derive(Debug, Clone, Serialize, Deserialize)]
    62→pub struct Gallops {
    63→    pub next_heat_seed: String,
    64→    pub heats: std::collections::HashMap<String, Heat>,
    65→}
    66→
    67→// Validation helper functions
    68→
    69→/// Check if string contains only URL-safe base64 characters
    70→fn is_base64(s: &str) -> bool {
    71→    s.bytes().all(|b| CHARSET.contains(&b))
    72→}
    73→
    74→/// Check if string is valid kebab-case (non-empty, lowercase alphanumeric with hyphens)
    75→fn is_kebab_case(s: &str) -> bool {
    76→    if s.is_empty() {
    77→        return false;
    78→    }
    79→    // Pattern: [a-z0-9]+(-[a-z0-9]+)*
    80→    let parts: Vec<&str> = s.split('-').collect();
    81→    for part in parts {
    82→        if part.is_empty() {
    83→            return false;
    84→        }
    85→        if !part.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit()) {
    86→            return false;
    87→        }
    88→    }
    89→    true
    90→}
    91→
    92→/// Check if string matches YYMMDD format
    93→fn is_yymmdd(s: &str) -> bool {
    94→    if s.len() != 6 {
    95→        return false;
    96→    }
    97→    s.chars().all(|c| c.is_ascii_digit())
    98→}
    99→
   100→/// Check if string matches YYMMDD-HHMM format
   101→fn is_yymmdd_hhmm(s: &str) -> bool {
   102→    if s.len() != 11 {
   103→        return false;
   104→    }
   105→    let parts: Vec<&str> = s.split('-').collect();
   106→    if parts.len() != 2 {
   107→        return false;
   108→    }
   109→    parts[0].len() == 6
   110→        && parts[0].chars().all(|c| c.is_ascii_digit())
   111→        && parts[1].len() == 4
   112→        && parts[1].chars().all(|c| c.is_ascii_digit())
   113→}
   114→
   115→impl Gallops {
   116→    /// Load Gallops from a file path
   117→    pub fn load(path: &Path) -> Result<Self, String> {
   118→        let content = fs::read_to_string(path)
   119→            .map_err(|e| format!("Failed to read file '{}': {}", path.display(), e))?;
   120→
   121→        let gallops: Gallops = serde_json::from_str(&content)
   122→            .map_err(|e| format!("Failed to parse JSON: {}", e))?;
   123→
   124→        Ok(gallops)
   125→    }
   126→
   127→    /// Save Gallops to a file path (atomic write)
   128→    pub fn save(&self, path: &Path) -> Result<(), String> {
   129→        // Serialize to pretty JSON
   130→        let content = serde_json::to_string_pretty(self)
   131→            .map_err(|e| format!("Failed to serialize JSON: {}", e))?;
   132→
   133→        // Create temp file in same directory for atomic rename
   134→        let parent = path.parent().ok_or_else(|| "Invalid path: no parent directory".to_string())?;
   135→        let temp_path = parent.join(format!(".tmp.{}.json", std::process::id()));
   136→
   137→        // Write to temp file
   138→        let mut file = fs::File::create(&temp_path)
   139→            .map_err(|e| format!("Failed to create temp file: {}", e))?;
   140→        file.write_all(content.as_bytes())
   141→            .map_err(|e| format!("Failed to write temp file: {}", e))?;
   142→        file.sync_all()
   143→            .map_err(|e| format!("Failed to sync temp file: {}", e))?;
   144→        drop(file);
   145→
   146→        // Atomic rename
   147→        fs::rename(&temp_path, path)
   148→            .map_err(|e| format!("Failed to rename temp file to target: {}", e))?;
   149→
   150→        Ok(())
   151→    }
   152→
   153→    /// Validate the Gallops structure
   154→    ///
   155→    /// Returns Ok(()) if valid, Err(Vec<String>) with all validation errors otherwise.
   156→    pub fn validate(&self) -> Result<(), Vec<String>> {
   157→        let mut errors = Vec::new();
   158→
   159→        // Rule 1: next_heat_seed must be 2 URL-safe base64 characters
   160→        if self.next_heat_seed.len() != 2 {
   161→            errors.push(format!(
   162→                "next_heat_seed must be 2 characters, got {}",
   163→                self.next_heat_seed.len()
   164→            ));
   165→        } else if !is_base64(&self.next_heat_seed) {
   166→            errors.push(format!(
   167→                "next_heat_seed contains invalid base64 characters: '{}'",
   168→                self.next_heat_seed
   169→            ));
   170→        }
   171→
   172→        // Rule 2: heats object exists (implicitly satisfied by struct)
   173→
   174→        // Validate each Heat
   175→        for (heat_key, heat) in &self.heats {
   176→            self.validate_heat(heat_key, heat, &mut errors);
   177→        }
   178→
   179→        if errors.is_empty() {
   180→            Ok(())
   181→        } else {
   182→            Err(errors)
   183→        }
   184→    }
   185→
   186→    fn validate_heat(&self, heat_key: &str, heat: &Heat, errors: &mut Vec<String>) {
   187→        let heat_ctx = format!("Heat '{}'", heat_key);
   188→
   189→        // Rule 3: Heat key must match ₣[A-Za-z0-9_-]{2}
   190→        if !heat_key.starts_with('₣') {
   191→            errors.push(format!("{}: key must start with '₣'", heat_ctx));
   192→        } else {
   193→            let suffix = &heat_key[3..]; // ₣ is 3 bytes in UTF-8
   194→            if suffix.len() != 2 {
   195→                errors.push(format!(
   196→                    "{}: key must have 2 base64 chars after '₣', got {}",
   197→                    heat_ctx,
   198→                    suffix.len()
   199→                ));
   200→            } else if !is_base64(suffix) {
   201→                errors.push(format!(
   202→                    "{}: key contains invalid base64 characters",
   203→                    heat_ctx
   204→                ));
   205→            }
   206→        }
   207→
   208→        // Rule 4: Required Heat fields
   209→        // silks (non-empty kebab-case)
   210→        if !is_kebab_case(&heat.silks) {
   211→            errors.push(format!(
   212→                "{}: silks must be non-empty kebab-case, got '{}'",
   213→                heat_ctx, heat.silks
   214→            ));
   215→        }
   216→
   217→        // creation_time (YYMMDD)
   218→        if !is_yymmdd(&heat.creation_time) {
   219→            errors.push(format!(
   220→                "{}: creation_time must be YYMMDD format, got '{}'",
   221→                heat_ctx, heat.creation_time
   222→            ));
   223→        }
   224→
   225→        // status (validated by serde enum)
   226→
   227→        // next_pace_seed (3 URL-safe base64 characters)
   228→        if heat.next_pace_seed.len() != 3 {
   229→            errors.push(format!(
   230→                "{}: next_pace_seed must be 3 characters, got {}",
   231→                heat_ctx,
   232→                heat.next_pace_seed.len()
   233→            ));
   234→        } else if !is_base64(&heat.next_pace_seed) {
   235→            errors.push(format!(
   236→                "{}: next_pace_seed contains invalid base64 characters",
   237→                heat_ctx
   238→            ));
   239→        }
   240→
   241→        // Extract heat identity (base64 part without prefix) for pace validation
   242→        let heat_identity = if heat_key.starts_with('₣') && heat_key.len() >= 5 {
   243→            Some(&heat_key[3..]) // ₣ is 3 bytes
   244→        } else {
   245→            None
   246→        };
   247→
   248→        // Rule 5: order array and paces object must have identical key sets
   249→        let order_set: HashSet<&String> = heat.order.iter().collect();
   250→        let _paces_set: HashSet<&String> = heat.paces.keys().collect();
   251→
   252→        if order_set.len() != heat.order.len() {
   253→            errors.push(format!("{}: order array contains duplicate entries", heat_ctx));
   254→        }
   255→
   256→        let in_order_not_paces: Vec<_> = heat
   257→            .order
   258→            .iter()
   259→            .filter(|k| !heat.paces.contains_key(*k))
   260→            .collect();
   261→        let in_paces_not_order: Vec<_> = heat
   262→            .paces
   263→            .keys()
   264→            .filter(|k| !order_set.contains(k))
   265→            .collect();
   266→
   267→        if !in_order_not_paces.is_empty() {
   268→            errors.push(format!(
   269→                "{}: order contains keys not in paces: {:?}",
   270→                heat_ctx, in_order_not_paces
   271→            ));
   272→        }
   273→        if !in_paces_not_order.is_empty() {
   274→            errors.push(format!(
   275→                "{}: paces contains keys not in order: {:?}",
   276→                heat_ctx, in_paces_not_order
   277→            ));
   278→        }
   279→
   280→        // Validate each Pace
   281→        for (pace_key, pace) in &heat.paces {
   282→            self.validate_pace(&heat_ctx, heat_identity, pace_key, pace, errors);
   283→        }
   284→    }
   285→
   286→    fn validate_pace(
   287→        &self,
   288→        heat_ctx: &str,
   289→        heat_identity: Option<&str>,
   290→        pace_key: &str,
   291→        pace: &Pace,
   292→        errors: &mut Vec<String>,
   293→    ) {
   294→        let pace_ctx = format!("{} Pace '{}'", heat_ctx, pace_key);
   295→
   296→        // Rule 6: Pace key must match ₢[A-Za-z0-9_-]{5}
   297→        if !pace_key.starts_with('₢') {
   298→            errors.push(format!("{}: key must start with '₢'", pace_ctx));
   299→        } else {
   300→            let suffix = &pace_key[3..]; // ₢ is 3 bytes in UTF-8
   301→            if suffix.len() != 5 {
   302→                errors.push(format!(
   303→                    "{}: key must have 5 base64 chars after '₢', got {}",
   304→                    pace_ctx,
   305→                    suffix.len()
   306→                ));
   307→            } else {
   308→                if !is_base64(suffix) {
   309→                    errors.push(format!(
   310→                        "{}: key contains invalid base64 characters",
   311→                        pace_ctx
   312→                    ));
   313→                }
   314→                // Pace must embed parent Heat identity (first 2 chars)
   315→                if let Some(heat_id) = heat_identity {
   316→                    if !suffix.starts_with(heat_id) {
   317→                        errors.push(format!(
   318→                            "{}: key must embed parent heat identity '{}', got '{}'",
   319→                            pace_ctx,
   320→                            heat_id,
   321→                            &suffix[..2.min(suffix.len())]
   322→                        ));
   323→                    }
   324→                }
   325→            }
   326→        }
   327→
   328→        // Rule 7: Pace must have silks (non-empty kebab-case)
   329→        if !is_kebab_case(&pace.silks) {
   330→            errors.push(format!(
   331→                "{}: silks must be non-empty kebab-case, got '{}'",
   332→                pace_ctx, pace.silks
   333→            ));
   334→        }
   335→
   336→        // Rule 7: tacks must be non-empty array
   337→        if pace.tacks.is_empty() {
   338→            errors.push(format!("{}: tacks array must not be empty", pace_ctx));
   339→        }
   340→
   341→        // Validate each Tack
   342→        for (i, tack) in pace.tacks.iter().enumerate() {
   343→            self.validate_tack(&pace_ctx, i, tack, errors);
   344→        }
   345→    }
   346→
   347→    fn validate_tack(&self, pace_ctx: &str, index: usize, tack: &Tack, errors: &mut Vec<String>) {
   348→        let tack_ctx = format!("{} Tack[{}]", pace_ctx, index);
   349→
   350→        // Rule 8: ts must be YYMMDD-HHMM
   351→        if !is_yymmdd_hhmm(&tack.ts) {
   352→            errors.push(format!(
   353→                "{}: ts must be YYMMDD-HHMM format, got '{}'",
   354→                tack_ctx, tack.ts
   355→            ));
   356→        }
   357→
   358→        // Rule 8: text must be non-empty
   359→        if tack.text.is_empty() {
   360→            errors.push(format!("{}: text must not be empty", tack_ctx));
   361→        }
   362→
   363→        // Rule 9: direction presence depends on state
   364→        match tack.state {
   365→            PaceState::Primed => {
   366→                match &tack.direction {
   367→                    None => {
   368→                        errors.push(format!(
   369→                            "{}: direction is required when state is 'primed'",
   370→                            tack_ctx
   371→                        ));
   372→                    }
   373→                    Some(d) if d.is_empty() => {
   374→                        errors.push(format!(
   375→                            "{}: direction must not be empty when state is 'primed'",
   376→                            tack_ctx
   377→                        ));
   378→                    }
   379→                    _ => {}
   380→                }
   381→            }
   382→            _ => {
   383→                if tack.direction.is_some() {
   384→                    errors.push(format!(
   385→                        "{}: direction must be absent when state is not 'primed'",
   386→                        tack_ctx
   387→                    ));
   388→                }
   389→            }
   390→        }
   391→    }
   392→}
