                silks: "test-pace-two".to_string(),
                tacks: vec![Tack {
                    ts: "260101-1300".to_string(),
                    state: PaceState::Complete,
                    text: "Completed pace".to_string(),
                    direction: None,
                }],
            },
        );

        let mut heats = HashMap::new();
        heats.insert(
