        let filter = Some(HeatStatus::Current);
        let matches = filter.as_ref().map_or(true, |f| &heat.status == f);
        assert!(matches);
    }

    #[test]
    fn test_heat_status_filter_retired() {
        let gallops = create_test_gallops();
        let heat = gallops.heats.get("₣AB").unwrap();

