#[derive(clap::Args, Debug)]
struct JjxNotchArgs {
    /// Active Heat identity (Firemark)
    firemark: String,

    /// Silks of the current pace
    #[arg(long)]
    pace: String,

    /// Commit message (if absent, claude generates from diff)
