/// Arguments for jjx_rein command
#[cfg(feature = "jjk")]
#[derive(clap::Args, Debug)]
struct JjxReinArgs {
    /// Target Heat identity (Firemark)
    firemark: String,

    /// Repository brand identifier (from arcanum installation)
    #[arg(long)]
    brand: String,

    /// Maximum entries to return
    #[arg(long, default_value = "50")]
    limit: usize,
