    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
    file: std::path::PathBuf,
}

/// Arguments for jjx_muster command
#[cfg(feature = "jjk")]
#[derive(clap::Args, Debug)]
struct JjxMusterArgs {
