        paces.insert(
            "₢ABAAB".to_string(),
            Pace {
                silks: "test-pace-two".to_string(),
                tacks: vec![Tack {
                    ts: "260101-1300".to_string(),
                    state: PaceState::Complete,
                    text: "Completed pace".to_string(),
                    direction: None,
                }],
            },
        );

        let mut heats = HashMap::new();
        heats.insert(
            "₣AB".to_string(),
            Heat {
                silks: "test-heat".to_string(),
                creation_time: "260101".to_string(),
