    fn write_temp_gallops(gallops: &Gallops) -> NamedTempFile {
        let mut file = NamedTempFile::new().unwrap();
        let json = serde_json::to_string_pretty(gallops).unwrap();
        file.write_all(json.as_bytes()).unwrap();
        file
    }

