        let gallops = create_test_gallops();
        let heat = gallops.heats.get("₣AB").unwrap();
        let expected_format = format!(
            "₣AB\t{}\tcurrent\t{}",
            heat.silks,
            heat.paces.len()
        );
        assert!(expected_format.contains("test-heat"));
        assert!(expected_format.contains("2")); // pace count
    }

